const items = $input.all();
let rows = "";
const tiposSet = new Set();

for (const item of items) {
  const data = item.json;
  const tipo = data.Tipo || 'Sin Tipo';
  tiposSet.add(tipo);

  rows += `
    <tr class="item-row" data-tipo="${tipo}">
      <td class="bold col-nombre" data-label="Nombre">${data.Nombre || 'Sin nombre'}</td>
      <td class="col-tipo" data-label="Tipo"><span class="tag">${tipo}</span></td>
      <td class="col-medio" data-label="Medio">${data.Medio || '-'}</td>
      <td class="col-longitud" data-label="Longitud">${data.Longitud || '-'}</td>
      <td class="notas col-nota" data-label="Notas">${data.Nota || '-'}</td>
      <td style="text-align: center;" class="col-numero" data-label="Cant.">${data.Numero || '0'}</td>
      <td style="text-align: center; white-space: nowrap;" data-label="Acciones">
        <button class="btn-action" onclick="prepararEdicion(this)" title="Editar">✏️</button>
        <button class="btn-action btn-delete" onclick="eliminarItem(this)" title="Eliminar">🗑️</button>
      </td>
    </tr>`;
}

const tiposArr = Array.from(tiposSet);
const tiposOptions = tiposArr.map(t => `<option value="${t}">${t}</option>`).join('');
const tiposMenu = tiposArr.map(t => `<a onclick="filtrarPorTipo('${t}')">📦 ${t}</a>`).join('');

const abrirScript = "<" + "script>";
const cerrarScript = "<" + "/script>";
const jsPdfLib = "<" + "script src='https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js'>" + cerrarScript;
const jsPdfAutoLib = "<" + "script src='https://cdnjs.cloudflare.com/ajax/libs/jspdf-autotable/3.5.28/jspdf.plugin.autotable.min.js'>" + cerrarScript;

