  <div class="section-title">FILTRAR POR TIPO</div>
  ${tiposMenu}

  <div class="section-title" style="margin-top: 20px;">AJUSTES</div>
  <div class="switch-container">
    <span>🌙 Dark Mode</span>
    <label class="switch">
      <input type="checkbox" id="darkModeToggle" onchange="toggleDarkMode()">
      <span class="slider"></span>
    </label>
  </div>
</div>
<div id="main">
  <div class="nav-bar">
    <button class="menu-btn" onclick="toggleNav()">☰</button>
    <h2 id="view-title">Inventario General</h2>
  </div>

  <div class="action-bar">
    <input type="text" id="searchInput" placeholder="🔍 Buscar por nombre, tipo, notas..." onkeyup="ejecutarFiltros()">

    <button class="btn-secondary" id="btn-fullscreen" onclick="toggleFullScreen()">🔲 Pantalla Completa</button>

    <div class="dropdown">
      <button class="btn-secondary btn-export" onclick="toggleExportMenu()">📥 Exportar ▼</button>
      <div id="exportMenu" class="dropdown-content">
        <a onclick="exportarCSV()">📄 Descargar CSV</a>
        <a onclick="exportarExcel()">📊 Descargar Excel</a>
        <a onclick="exportarPDF()">📕 Descargar PDF</a>
      </div>
    </div>
  </div>

  <div class="container">
    <table id="miTabla">
      <thead>
        <tr>
          <th onclick="sortTable(0, 'string')">Nombre <span class="sort-icon" id="icon-0">↕</span></th>
          <th onclick="sortTable(1, 'string')">Tipo <span class="sort-icon" id="icon-1">↕</span></th>
          <th onclick="sortTable(2, 'string')">Medio <span class="sort-icon" id="icon-2">↕</span></th>
          <th onclick="sortTable(3, 'string')">Longitud <span class="sort-icon" id="icon-3">↕</span></th>
          <th onclick="sortTable(4, 'string')">Notas <span class="sort-icon" id="icon-4">↕</span></th>
          <th style="text-align:center" onclick="sortTable(5, 'number')">Cant. <span class="sort-icon" id="icon-5">↕</span></th>
          <th style="text-align:center" class="no-sort">Acciones</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  </div>
</div>

<div id="modalItem" class="modal">
  <div class="modal-content">
    <button class="btn-close" onclick="closeModal('modalItem')">&times;</button>
    <h3 id="modalTitle">Nuevo Item</h3>
    <form id="formItem">
      <input type="text" id="formNombre" name="Nombre" required placeholder="Nombre del producto">
      <div class="tipo-container">
        <select id="selectTipo" name="Tipo">
          <option value="">Selecciona Tipo...</option>
          ${tiposOptions}
        </select>
        <input id="inputTipoManual" type="text" name="TipoManual" class="hidden" placeholder="Nuevo tipo...">
        <button type="button" class="btn-plus" onclick="toggleTipoManual()">+</button>
      </div>
      <input type="text" id="formMedio" name="Medio" placeholder="Medio">
      <input type="text" id="formLongitud" name="Longitud" placeholder="Longitud">
      <input type="number" id="formNumero" name="Numero" required placeholder="Cantidad">
      <textarea id="formNota" name="Nota" placeholder="Notas"></textarea>
      <button type="submit" class="btn-save" id="btnSubmit">GUARDAR</button>
    </form>
  </div>
</div>

${abrirScript}
  let navOpen = false;
  let esTipoManual = false;
  let filtroActualTipo = "Todos";
  let sortDirections = [0, 0, 0, 0, 0, 0];

  // --- LÓGICA DARK MODE ---
  function toggleDarkMode() {
    const isDark = document.getElementById('darkModeToggle').checked;
    if(isDark) {
      document.body.classList.add('dark-theme');
      localStorage.setItem('invDarkMode', 'true');
    } else {
      document.body.classList.remove('dark-theme');
      localStorage.setItem('invDarkMode', 'false');
    }
  }

  // Cargar preferencia al iniciar
  if(localStorage.getItem('invDarkMode') === 'true') {
    document.body.classList.add('dark-theme');
    document.getElementById('darkModeToggle').checked = true;
  }

  function toggleFullScreen() {
    const btn = document.getElementById('btn-fullscreen');
    if (!document.fullscreenElement && !document.webkitFullscreenElement) {
      const docElm = document.documentElement;
      if (docElm.requestFullscreen) docElm.requestFullscreen();
      else if (docElm.webkitRequestFullscreen) docElm.webkitRequestFullscreen();
      btn.innerText = '🔳 Salir P. Completa';
    } else {
      if (document.exitFullscreen) document.exitFullscreen();
      else if (document.webkitExitFullscreen) document.webkitExitFullscreen();
      btn.innerText = '🔲 Pantalla Completa';
    }
  }

  document.addEventListener('fullscreenchange', exitHandler);
  document.addEventListener('webkitfullscreenchange', exitHandler);
  function exitHandler() {
    if (!document.fullscreenElement && !document.webkitIsFullScreen) {
      document.getElementById('btn-fullscreen').innerText = '🔲 Pantalla Completa';
    }
  }

  function sortTable(columnIndex, type) {
    const tbody = document.querySelector("#miTabla tbody");
    const rows = Array.from(tbody.querySelectorAll(".item-row"));
    let direction = sortDirections[columnIndex] === 1 ? -1 : 1;
    sortDirections = [0, 0, 0, 0, 0, 0];
    sortDirections[columnIndex] = direction;

    for(let i=0; i<6; i++) {
      const icon = document.getElementById('icon-'+i);
      if(icon) {
        icon.innerText = i === columnIndex ? (direction === 1 ? '↓' : '↑') : '↕';
        icon.className = i === columnIndex ? 'sort-icon sort-active' : 'sort-icon';
      }
    }

    rows.sort((a, b) => {
      let valA = a.querySelectorAll("td")[columnIndex].innerText.trim();
      let valB = b.querySelectorAll("td")[columnIndex].innerText.trim();
      if (type === 'number') {
        valA = parseFloat(valA) || 0; valB = parseFloat(valB) || 0;
        return (valA - valB) * direction;
      } else {
        return valA.localeCompare(valB, 'es', { numeric: true }) * direction;
      }
    });
    rows.forEach(row => tbody.appendChild(row));
  }

  function toggleNav() {
    const s = document.getElementById("sidebar"), m = document.getElementById("main");
    s.style.width = navOpen ? "0" : "250px";
    if(window.innerWidth > 768) { m.style.marginLeft = navOpen ? "0" : "250px"; }
    navOpen = !navOpen;
  }

  function openModal(id) { document.getElementById(id).style.display = 'flex'; if(navOpen) toggleNav(); }
  function closeModal(id) { document.getElementById(id).style.display = 'none'; }

  function toggleExportMenu() { document.getElementById("exportMenu").classList.toggle("show-dropdown"); }
  window.onclick = function(event) {
    if (!event.target.matches('.btn-export')) {
      const dropdowns = document.getElementsByClassName("dropdown-content");
      for (let i = 0; i < dropdowns.length; i++) {
        if (dropdowns[i].classList.contains('show-dropdown')) dropdowns[i].classList.remove('show-dropdown');
      }
    }
  }

  function obtenerDatosTabla() {
    const data = [];
    const cabeceras = [];
    document.querySelectorAll('thead th').forEach((th, index) => {
      if(index < 6) cabeceras.push(th.innerText.replace(/[↑↓↕]/g, '').trim()); 
    });
    data.push(cabeceras);
    document.querySelectorAll('.item-row').forEach(tr => {
      if (tr.style.display !== 'none') {
        const filaData = [];
        tr.querySelectorAll('td').forEach((td, index) => { if(index < 6) filaData.push(td.innerText.trim()); });
        data.push(filaData);
      }
    });
    return data;
  }

  function exportarCSV() {
    const data = obtenerDatosTabla();
    let csvStr = "";
    data.forEach(row => { csvStr += row.map(c => '"' + c.replace(/"/g, '""') + '"').join(",") + "\\r\\n"; });
    const link = document.createElement("a");
    link.href = "data:text/csv;charset=utf-8," + encodeURIComponent(csvStr); 
    link.download = "Inventario_IT.csv";
    document.body.appendChild(link); link.click(); link.remove();
  }

  function exportarExcel() {
    const data = obtenerDatosTabla();
    let tableHTML = "<table><thead><tr>";
    data[0].forEach(h => tableHTML += "<th>" + h + "</th>");
    tableHTML += "</tr></thead><tbody>";
    for(let i = 1; i < data.length; i++) {
      tableHTML += "<tr>";
      data[i].forEach(c => tableHTML += "<td>" + c + "</td>");
      tableHTML += "</tr>";
    }
    tableHTML += "</tbody></table>";
    const template = '<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel"><head><meta charset="UTF-8"></head><body>' + tableHTML + '</body></html>';
    const blob = new Blob([template], { type: 'application/vnd.ms-excel' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob); link.download = "Inventario_IT.xls";
    document.body.appendChild(link); link.click(); link.remove();
  }

  function exportarPDF() {
    const { jsPDF } = window.jspdf;
    const doc = new jsPDF();
    const data = obtenerDatosTabla();
    doc.setFontSize(18);
    doc.text(document.getElementById('view-title').innerText, 14, 20);
    doc.autoTable({ head: [data[0]], body: data.slice(1), startY: 25, styles: { font: 'helvetica', fontSize: 9 }, headStyles: { fillColor: [26, 26, 26] }, alternateRowStyles: { fillColor: [248, 249, 250] } });
    doc.save('Inventario_IT.pdf');
  }

  function resetFormYAbrir() {
    document.getElementById('formItem').reset();
    document.getElementById('formNombre').disabled = false;
    document.getElementById('modalTitle').innerText = "Nuevo Item";
    document.getElementById('btnSubmit').innerText = "GUARDAR NUEVO";
    if(esTipoManual) toggleTipoManual();
    openModal('modalItem');
  }

  function prepararEdicion(btn) {
    const fila = btn.closest('tr');
    document.getElementById('modalTitle').innerText = "Editar Item";
    document.getElementById('btnSubmit').innerText = "ACTUALIZAR DATOS";
    const nombre = fila.querySelector('.col-nombre').innerText;
    document.getElementById('formNombre').value = nombre;
    document.getElementById('formNombre').disabled = true;
    document.getElementById('selectTipo').value = fila.querySelector('.col-tipo').innerText.trim();
    document.getElementById('formMedio').value = fila.querySelector('.col-medio').innerText.replace('-', '');
    document.getElementById('formLongitud').value = fila.querySelector('.col-longitud').innerText.replace('-', '');
    document.getElementById('formNumero').value = fila.querySelector('.col-numero').innerText;
    document.getElementById('formNota').value = fila.querySelector('.col-nota').innerText.replace('-', '');
    openModal('modalItem');
  }

  async function eliminarItem(btn) {
    const fila = btn.closest('tr');
    const nombre = fila.querySelector('.col-nombre').innerText;
    if (confirm('¿Estás seguro de que deseas eliminar "' + nombre + '"?')) {
